}

async fn replace_catalog(
    db: &sea_orm::DatabaseConnection,
    catalog: AppCatalog,
) -> Result<(), ApiError> {
    schema::reset_metadata_schema(db)
        .await
        .map_err(ApiError::internal)?;
    schema::migrate_metadata_schema(db)
        .await
        .map_err(ApiError::internal)?;
    ensure_metadata_lock_row(db)
        .await
        .map_err(ApiError::internal)?;
    seed_catalog(db, catalog).await
}

